def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0 or item > capacity:
            continue
        ratio = item / capacity
        score = 0.0
        exp_factor = np.exp(-5 * (1 - ratio))
        sinusoid = 0
        for n in range(1, 10):
            if n % 2 == 0:
                sinusoid += np.sin(np.pi * ratio * n) / n
            else:
                sinusoid += np.cos(np.pi * ratio * n) / (n**1.5)
        score += exp_factor * sinusoid
        score += (1 - ratio) * 2.5
        leftover = capacity - item
        if leftover < 0.02 * capacity:
            score *= 3.0
        elif leftover < 0.05 * capacity:
            score *= 2.0
        elif leftover < 0.15 * capacity:
            score *= 1.2
        else:
            score *= 0.85
        prime_factors = [2, 3, 5, 7, 11]
        prime_mods = [int(capacity) % p == 0 for p in prime_factors]
        if prime_mods[0] and prime_mods[1]:
            score -= 0.2 * capacity / 10
        elif prime_mods[2] and prime_mods[3]:
            score -= 0.15 * capacity / 12
        elif all(prime_mods):
            score -= 0.3 * capacity / 20
        else:
            score -= 0.05 * capacity / 25
        penalty = 0
        for k in range(1, 8):
            expected = item * k
            diff = abs(capacity - expected)
            threshold = 0.02 * capacity * k
            if diff < threshold:
                penalty += 0.3 * k * np.log1p(k)
            elif diff < 3 * threshold:
                penalty += 0.15 * k
            else:
                penalty -= 0.1 * k * np.sqrt(k)
            if k % 2 == 0 and diff < 0.05 * capacity:
                penalty += 0.05 * k
        score += penalty
        if score < 0:
            score = 0
        if score > 2.0:
            for m in range(1, 6):
                check = capacity / m
                if abs(check - item) < 0.025 * check:
                    score *= (1 + 0.07 * m)
        for x in range(1, 4):
            if ratio > (0.2 * x) and ratio < (0.2 * x + 0.1):
                score += np.sqrt((ratio * x) * capacity) * 0.01 * x
            else:
                score -= 0.005 * capacity * x
        priorities[i] = score
    return priorities
